const input = $json ?? {};
const binary = $binary ?? {};

function safeText(value, fallback = '') {
  const text = String(value ?? '').trim();
  return text || fallback;
}

function asNumber(value, fallback, min, max) {
  const n = Number(value);
  if (!Number.isFinite(n)) return fallback;
  if (Number.isFinite(min) && n < min) return min;
  if (Number.isFinite(max) && n > max) return max;
  return n;
}

function normalizeText(value) {
  return String(value ?? '').replace(/\r\n/g, '\n').trim();
}

function readFirstBinaryText(binaryMap) {
  const keys = Object.keys(binaryMap ?? {});
  if (keys.length === 0) return '';
  const first = binaryMap[keys[0]];
  const base64 = safeText(first?.data);
  if (!base64 || base64 === 'filesystem-v2' || base64.startsWith('filesystem-v2:')) return '';
  try {
    return Buffer.from(base64, 'base64').toString('utf8');
  } catch (_) {
    return '';
  }
}

function splitTextIntoChunks(text, maxCharsChunk) {
  const raw = normalizeText(text);
  if (!raw) return [];

  const paragraphs = raw.split(/[\r\n]+/);
  const finalChunks = [];

  for (const paragraphRaw of paragraphs) {
    const paragraph = String(paragraphRaw ?? '').trim();
    if (!paragraph) continue;

    const sentences = paragraph
      .split(/(?<=[\.!?\u2026])\s+/)
      .map((x) => String(x ?? '').trim())
      .filter(Boolean);

    let buffer = '';

    for (const sentence of sentences) {
      if (sentence.length > maxCharsChunk) {
        if (buffer) {
          finalChunks.push(buffer);
          buffer = '';
        }

        const subParts = sentence
          .split(/(?<=[,;:\-\u2013\u2014])\s+/)
          .map((x) => String(x ?? '').trim())
          .filter(Boolean);

        for (const part of subParts) {
          const nextLen = buffer ? (buffer.length + 1 + part.length) : part.length;
          if (nextLen <= maxCharsChunk) {
            buffer = buffer ? (buffer + ' ' + part) : part;
            continue;
          }

          if (buffer) {
            finalChunks.push(buffer);
          }

          buffer = part;
          if (buffer.length > maxCharsChunk) {
            const words = buffer.split(/\s+/).filter(Boolean);
            let current = '';

            for (const word of words) {
              if (current && (current.length + 1 + word.length > maxCharsChunk)) {
                finalChunks.push(current);
                current = word;
              } else {
                current = current ? (current + ' ' + word) : word;
              }
            }

            buffer = current;
          }
        }
      } else if (buffer && (buffer.length + 1 + sentence.length > maxCharsChunk)) {
        finalChunks.push(buffer);
        buffer = sentence;
      } else {
        buffer = buffer ? (buffer + ' ' + sentence) : sentence;
      }
    }

    if (buffer) {
      finalChunks.push(buffer);
    }
  }

  return finalChunks.map((x) => x.trim()).filter(Boolean);
}

const text = normalizeText(input.text ?? readFirstBinaryText(binary));

const rawMode = safeText(input.mode, 'auto').toLowerCase();
const mode = ['auto', 'sentence', 'fulltext', 'fullText'].includes(rawMode)
  ? (rawMode === 'fulltext' ? 'fullText' : rawMode)
  : 'auto';

const maxCharsChunk = Math.floor(asNumber(input.maxCharsChunk, 256, 32, 3000));
const batchSize = Math.floor(asNumber(input.batchSize, 1, 1, 20));

const rawJoinMode = safeText(input.joinMode, 'silence').toLowerCase();
const joinMode = rawJoinMode === 'crossfade' ? 'crossfade' : 'silence';

const silenceSeconds = asNumber(input.silenceSeconds, 0.15, 0, 10);
const crossfadeSeconds = asNumber(input.crossfadeSeconds, 0, 0, 5);
const retry = Math.floor(asNumber(input.retry, 2, 0, 8));
const requestTimeoutSec = Math.floor(asNumber(input.requestTimeoutSec, 120, 5, 1800));
const requestId = safeText(input.requestId, 'req-' + Date.now().toString(36));
const voiceId = safeText(input.voiceId);

const baseUrlRaw = safeText(input.ttsApiBaseUrl, 'http://127.0.0.1:8001');
const ttsApiBaseUrl = baseUrlRaw.replace(/\/$/, '');

if (!text) {
  return {
    requestId,
    text: '',
    voiceId,
    mode,
    maxCharsChunk,
    batchSize,
    joinMode,
    silenceSeconds,
    crossfadeSeconds,
    retry,
    requestTimeoutSec,
    ttsApiBaseUrl,
    chunks: [],
    chunksTotal: 0,
    status: 'failed',
    errorReason: 'empty_text',
  };
}

let effectiveMode = mode;
if (effectiveMode === 'auto') {
  effectiveMode = text.length <= maxCharsChunk ? 'sentence' : 'fullText';
}

const chunkTexts = effectiveMode === 'sentence'
  ? [text]
  : splitTextIntoChunks(text, maxCharsChunk);

const chunks = chunkTexts.map((chunkText, index) => ({
  chunkIndex: index,
  text: chunkText,
}));

return {
  requestId,
  text,
  voiceId,
  mode: effectiveMode,
  maxCharsChunk,
  batchSize,
  joinMode,
  silenceSeconds,
  crossfadeSeconds,
  retry,
  requestTimeoutSec,
  ttsApiBaseUrl,
  chunks,
  chunksTotal: chunks.length,
  status: chunks.length > 0 ? 'planned' : 'failed',
  errorReason: chunks.length > 0 ? null : 'empty_chunks',
};

const input = $json ?? {};
const helperContext = this;

function safeText(value, fallback = '') {
  const text = String(value ?? '').trim();
  return text || fallback;
}

function asInt(value, fallback = 0, min = 0, max = 1000000) {
  const n = Number(value);
  const normalized = Number.isFinite(n) ? Math.floor(n) : fallback;
  return Math.min(max, Math.max(min, normalized));
}

function parseVoicesPayload(payload) {
  if (Array.isArray(payload)) return payload;
  if (payload && Array.isArray(payload.voices)) return payload.voices;
  if (payload && Array.isArray(payload.data)) return payload.data;
  return [];
}

function getHeader(headers, key, fallback = '') {
  if (!headers || typeof headers !== 'object') return fallback;
  const target = key.toLowerCase();
  for (const [name, value] of Object.entries(headers)) {
    if (String(name).toLowerCase() === target) {
      return safeText(value, fallback);
    }
  }
  return fallback;
}

function decodeResponseBodyToBuffer(body) {
  if (Buffer.isBuffer(body)) return body;

  if (body && typeof body === 'object' && body.type === 'Buffer' && Array.isArray(body.data)) {
    return Buffer.from(body.data);
  }

  if (typeof body === 'string') {
    const compact = body.replace(/\s+/g, '');
    const looksBase64 = compact.length > 0
      && compact.length % 4 === 0
      && /^[A-Za-z0-9+/=]+$/.test(compact);

    if (looksBase64) {
      try {
        return Buffer.from(compact, 'base64');
      } catch (_) {
        // Fallback below
      }
    }

    // If the runtime already coerced binary into UTF-8 string with replacement chars,
    // bytes are no longer recoverable here.
    return Buffer.from(body, 'binary');
  }

  return Buffer.from(JSON.stringify(body ?? ''));
}

async function requestWithTimeout({
  url,
  method,
  headers,
  timeoutMs,
  jsonBody,
  rawBody,
  expectBinary = false,
}) {
  if (!helperContext || !helperContext.helpers) {
    throw new Error('http_helper_missing');
  }

  const timeout = Math.max(1000, asInt(timeoutMs, 5000, 1, 3600000));

  // Prefer legacy request helper for binary: it preserves raw bytes via encoding=null.
  if (typeof helperContext.helpers.request === 'function') {
    const options = {
      method,
      uri: url,
      headers: headers ?? {},
      timeout,
      resolveWithFullResponse: true,
      simple: false,
    };

    if (typeof rawBody === 'string') {
      options.body = rawBody;
      options.json = false;
    } else if (jsonBody !== undefined) {
      options.body = jsonBody;
      options.json = true;
    }

    if (expectBinary) {
      options.encoding = null;
      options.json = false;
    }

    return helperContext.helpers.request(options);
  }

  if (typeof helperContext.helpers.httpRequest === 'function') {
    const options = {
      method,
      url,
      headers: headers ?? {},
      timeout,
      returnFullResponse: true,
    };

    if (typeof rawBody === 'string') {
      options.body = rawBody;
      options.json = false;
    } else if (jsonBody !== undefined) {
      options.body = jsonBody;
      options.json = true;
    }

    if (expectBinary) {
      options.encoding = 'base64';
      options.json = false;
    }

    return helperContext.helpers.httpRequest(options);
  }

  throw new Error('http_helper_unavailable');
}

async function resolveVoiceId(baseUrl, preferredVoiceId, timeoutMs) {
  const fixed = safeText(preferredVoiceId);
  if (fixed) return fixed;

  const response = await requestWithTimeout({
    url: baseUrl + '/voices',
    method: 'GET',
    headers: { Accept: 'application/json' },
    timeoutMs,
  });

  const statusCode = asInt(response?.statusCode, 0, 0, 999);
  if (!(statusCode >= 200 && statusCode < 300)) {
    throw new Error('voices_http_' + String(statusCode));
  }

  const rawPayload = response?.body;
  const payload = typeof rawPayload === 'string'
    ? (() => {
        try {
          return JSON.parse(rawPayload);
        } catch (_) {
          return rawPayload;
        }
      })()
    : rawPayload;
  const voices = parseVoicesPayload(payload);

  for (const row of voices) {
    const id = safeText(row?.id, safeText(row?.voice_id));
    if (id) return id;
  }

  throw new Error('voices_empty');
}

function waitMs(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

async function runChunk({ baseUrl, voiceId, chunk, retry, timeoutMs, startedAt }) {
  const backoffs = [500, 1000, 2000];
  let lastError = 'stream_failed';

  for (let attempt = 1; attempt <= retry + 1; attempt += 1) {
    try {
      const response = await requestWithTimeout({
        url: baseUrl + '/stream',
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Accept: 'audio/wav,application/octet-stream,application/json',
        },
        rawBody: JSON.stringify({ text: chunk.text, voice_id: voiceId }),
        timeoutMs,
        expectBinary: true,
      });

      const statusCode = asInt(response?.statusCode, 0, 0, 999);
      const contentType = getHeader(response?.headers, 'content-type').toLowerCase();
      const body = response?.body;
      const buffer = decodeResponseBodyToBuffer(body);

      if (!(statusCode >= 200 && statusCode < 300)) {
        const responseText = buffer.toString('utf8').slice(0, 400);
        throw new Error('stream_http_' + String(statusCode) + (responseText ? ':' + responseText : ''));
      }

      if (buffer.length < 44) {
        throw new Error('stream_audio_too_short:' + String(buffer.length));
      }

      const isRiffWav = buffer.subarray(0, 4).toString('ascii') === 'RIFF'
        && buffer.subarray(8, 12).toString('ascii') === 'WAVE';

      if (!isRiffWav) {
        throw new Error('stream_invalid_wav_header');
      }

      if (!contentType.includes('audio/')) {
        const responseText = buffer.toString('utf8').slice(0, 400);
        throw new Error('stream_non_audio:' + responseText);
      }

      return {
        ...chunk,
        status: 'success',
        attempts: attempt,
        voiceId,
        wavBase64: buffer.toString('base64'),
        wavBytes: buffer.length,
        latencyMs: Date.now() - startedAt,
        errorReason: null,
      };
    } catch (error) {
      lastError = safeText(error?.message, 'stream_failed').slice(0, 500);
      if (attempt <= retry) {
        const backoff = backoffs[Math.min(attempt - 1, backoffs.length - 1)] ?? 2000;
        await waitMs(backoff);
      }
    }
  }

  return {
    ...chunk,
    status: 'failed',
    attempts: retry + 1,
    voiceId,
    wavBase64: '',
    wavBytes: 0,
    latencyMs: Date.now() - startedAt,
    errorReason: lastError,
  };
}

const workflowStartedAt = Date.now();
const chunks = Array.isArray(input.chunks) ? input.chunks : [];
const retry = asInt(input.retry, 2, 0, 8);
const batchSize = asInt(input.batchSize, 1, 1, 20);
const timeoutMs = asInt(input.requestTimeoutSec, 120, 5, 1800) * 1000;
const baseUrl = safeText(input.ttsApiBaseUrl, 'http://127.0.0.1:8001').replace(/\/$/, '');

if (chunks.length === 0) {
  return {
    ...input,
    status: 'failed',
    errorReason: 'empty_chunks',
    items: [],
    failedChunkIndexes: [],
    chunksSuccess: 0,
  };
}

let resolvedVoiceId = '';
try {
  resolvedVoiceId = await resolveVoiceId(baseUrl, input.voiceId, timeoutMs);
} catch (error) {
  return {
    ...input,
    status: 'failed',
    errorReason: safeText(error?.message, 'resolve_voice_failed'),
    items: chunks.map((chunk) => ({
      ...chunk,
      status: 'failed',
      attempts: 0,
      voiceId: '',
      wavBase64: '',
      wavBytes: 0,
      latencyMs: Date.now() - workflowStartedAt,
      errorReason: 'resolve_voice_failed',
    })),
    failedChunkIndexes: chunks.map((chunk) => chunk.chunkIndex),
    chunksSuccess: 0,
  };
}

const orderedResults = [];
let firstAudioLatencyMs = -1;

for (let index = 0; index < chunks.length; index += batchSize) {
  const batch = chunks.slice(index, index + batchSize);
  const results = await Promise.all(batch.map((chunk) => runChunk({
    baseUrl,
    voiceId: resolvedVoiceId,
    chunk,
    retry,
    timeoutMs,
    startedAt: workflowStartedAt,
  })));

  for (const result of results) {
    if (result.status === 'success' && firstAudioLatencyMs < 0) {
      firstAudioLatencyMs = result.latencyMs;
    }
    orderedResults.push(result);
  }
}

orderedResults.sort((a, b) => a.chunkIndex - b.chunkIndex);

const chunksSuccess = orderedResults.filter((item) => item.status === 'success').length;
const failedChunkIndexes = orderedResults.filter((item) => item.status !== 'success').map((item) => item.chunkIndex);

let status = 'success';
if (chunksSuccess === 0) {
  status = 'failed';
} else if (failedChunkIndexes.length > 0) {
  status = 'partialFailed';
}

return {
  ...input,
  voiceId: resolvedVoiceId,
  batchSizeUsed: batchSize,
  firstAudioLatencyMs: firstAudioLatencyMs < 0 ? null : firstAudioLatencyMs,
  items: orderedResults,
  chunksSuccess,
  failedChunkIndexes,
  status,
  errorReason: status === 'failed' ? 'all_chunks_failed' : null,
};

const input = $json ?? {};

function safeText(value, fallback = '') {
  const text = String(value ?? '').trim();
  return text || fallback;
}

function asNumber(value, fallback = 0, min = null, max = null) {
  const n = Number(value);
  if (!Number.isFinite(n)) return fallback;
  if (Number.isFinite(min) && n < min) return min;
  if (Number.isFinite(max) && n > max) return max;
  return n;
}

function clampInt16(value) {
  if (value > 32767) return 32767;
  if (value < -32768) return -32768;
  return value;
}

function buildWavHeader(dataLength, sampleRate, channels, bitsPerSample) {
  const blockAlign = channels * bitsPerSample / 8;
  const byteRate = sampleRate * blockAlign;
  const header = Buffer.alloc(44);

  header.write('RIFF', 0);
  header.writeUInt32LE(36 + dataLength, 4);
  header.write('WAVE', 8);
  header.write('fmt ', 12);
  header.writeUInt32LE(16, 16);
  header.writeUInt16LE(1, 20);
  header.writeUInt16LE(channels, 22);
  header.writeUInt32LE(sampleRate, 24);
  header.writeUInt32LE(byteRate, 28);
  header.writeUInt16LE(blockAlign, 32);
  header.writeUInt16LE(bitsPerSample, 34);
  header.write('data', 36);
  header.writeUInt32LE(dataLength, 40);

  return header;
}

function parseWavPcm(wavBuffer) {
  if (!wavBuffer || wavBuffer.length < 44) {
    throw new Error('wav_too_short');
  }

  const riff = wavBuffer.subarray(0, 4).toString('ascii');
  const wave = wavBuffer.subarray(8, 12).toString('ascii');
  if (riff !== 'RIFF' || wave !== 'WAVE') {
    throw new Error('wav_invalid_header');
  }

  let offset = 12;
  let sampleRate = 24000;
  let channels = 1;
  let bitsPerSample = 16;
  let audioFormat = 1;
  let dataStart = -1;
  let dataLength = 0;

  while (offset + 8 <= wavBuffer.length) {
    const chunkId = wavBuffer.subarray(offset, offset + 4).toString('ascii');
    const chunkSize = wavBuffer.readUInt32LE(offset + 4);
    const chunkDataStart = offset + 8;
    const chunkDataEnd = chunkDataStart + chunkSize;

    if (chunkDataStart > wavBuffer.length || chunkDataEnd > wavBuffer.length) {
      throw new Error('wav_invalid_chunk_size');
    }

    if (chunkId === 'fmt ') {
      if (chunkSize < 16) {
        throw new Error('wav_invalid_fmt');
      }
      audioFormat = wavBuffer.readUInt16LE(chunkDataStart);
      channels = wavBuffer.readUInt16LE(chunkDataStart + 2);
      sampleRate = wavBuffer.readUInt32LE(chunkDataStart + 4);
      bitsPerSample = wavBuffer.readUInt16LE(chunkDataStart + 14);
    } else if (chunkId === 'data') {
      dataStart = chunkDataStart;
      dataLength = chunkSize;
      break;
    }

    offset = chunkDataEnd + (chunkSize % 2);
  }

  if (dataStart < 0) {
    throw new Error('wav_missing_data_chunk');
  }

  if (audioFormat !== 1) {
    throw new Error('wav_unsupported_audio_format_' + String(audioFormat));
  }

  if (channels !== 1) {
    throw new Error('wav_unsupported_channels_' + String(channels));
  }

  if (bitsPerSample !== 16) {
    throw new Error('wav_unsupported_bits_' + String(bitsPerSample));
  }

  const remainingBytes = Math.max(0, wavBuffer.length - dataStart);
  let effectiveDataLength = dataLength;

  if (!Number.isFinite(effectiveDataLength) || effectiveDataLength < 0) {
    throw new Error('wav_invalid_data_length');
  }

  // Some servers return valid PCM but leave data chunk size as 0.
  // Fallback to actual remaining bytes instead of hard-failing.
  if (effectiveDataLength === 0 && remainingBytes > 0) {
    effectiveDataLength = remainingBytes;
  } else if (effectiveDataLength > remainingBytes) {
    effectiveDataLength = remainingBytes;
  }

  const dataEnd = Math.min(wavBuffer.length, dataStart + effectiveDataLength);
  let pcm = wavBuffer.subarray(dataStart, dataEnd);

  if (pcm.length <= 0) {
    throw new Error('wav_empty_data');
  }

  if (pcm.length % 2 !== 0) {
    pcm = pcm.subarray(0, pcm.length - 1);
  }

  if (pcm.length <= 0) {
    throw new Error('wav_empty_pcm');
  }

  return {
    pcm,
    sampleRate,
    channels,
    bitsPerSample,
  };
}

function crossfadePcm(prevPcm, nextPcm, crossfadeSeconds, sampleRate) {
  const requestedSamples = Math.floor(crossfadeSeconds * sampleRate);
  const maxSamples = Math.floor(Math.min(prevPcm.length, nextPcm.length) / 2);
  const samples = Math.min(requestedSamples, maxSamples);

  if (!Number.isFinite(samples) || samples <= 0) {
    return Buffer.concat([prevPcm, nextPcm]);
  }

  const overlapBytes = samples * 2;
  const prevHead = prevPcm.subarray(0, prevPcm.length - overlapBytes);
  const prevTail = prevPcm.subarray(prevPcm.length - overlapBytes);
  const nextHead = nextPcm.subarray(0, overlapBytes);
  const nextTail = nextPcm.subarray(overlapBytes);
  const mixed = Buffer.alloc(overlapBytes);

  for (let i = 0; i < samples; i += 1) {
    const a = prevTail.readInt16LE(i * 2) / 32768;
    const b = nextHead.readInt16LE(i * 2) / 32768;
    const t = (i + 1) / (samples + 1);
    const value = clampInt16(Math.round((a * (1 - t) + b * t) * 32767));
    mixed.writeInt16LE(value, i * 2);
  }

  return Buffer.concat([prevHead, mixed, nextTail]);
}

const items = Array.isArray(input.items) ? input.items : [];
const sortedItems = [...items].sort((a, b) => Number(a?.chunkIndex ?? 0) - Number(b?.chunkIndex ?? 0));

const requestedJoinMode = safeText(input.joinMode, 'silence').toLowerCase();
const silenceSecondsInput = asNumber(input.silenceSeconds, 0.15, 0, 10);
const crossfadeSecondsInput = asNumber(input.crossfadeSeconds, 0, 0, 5);
const silenceSeconds = requestedJoinMode === 'crossfade' ? 0 : silenceSecondsInput;
const crossfadeSeconds = requestedJoinMode === 'crossfade' ? crossfadeSecondsInput : 0;

const normalizedItems = sortedItems.map((item) => ({ ...item }));
const audioSegments = [];
let targetFormat = null;

for (const item of normalizedItems) {
  if (item.status !== 'success') {
    continue;
  }

  const wavBase64 = safeText(item.wavBase64);
  if (!wavBase64) {
    item.status = 'failed';
    item.errorReason = safeText(item.errorReason, 'missing_wav_base64');
    continue;
  }

  let wavBuffer = Buffer.alloc(0);
  try {
    wavBuffer = Buffer.from(wavBase64, 'base64');
  } catch (_) {
    item.status = 'failed';
    item.errorReason = 'wav_base64_decode_failed';
    continue;
  }

  try {
    const parsed = parseWavPcm(wavBuffer);

    if (!targetFormat) {
      targetFormat = {
        sampleRate: parsed.sampleRate,
        channels: parsed.channels,
        bitsPerSample: parsed.bitsPerSample,
      };
    } else if (
      parsed.sampleRate !== targetFormat.sampleRate
      || parsed.channels !== targetFormat.channels
      || parsed.bitsPerSample !== targetFormat.bitsPerSample
    ) {
      throw new Error('wav_format_mismatch');
    }

    audioSegments.push({
      chunkIndex: Number(item.chunkIndex ?? 0),
      pcm: parsed.pcm,
    });
  } catch (error) {
    item.status = 'failed';
    item.errorReason = safeText(error?.message, 'wav_parse_failed').slice(0, 200);
  }
}

audioSegments.sort((a, b) => a.chunkIndex - b.chunkIndex);

let joinedPcm = Buffer.alloc(0);
const sampleRate = Number(targetFormat?.sampleRate ?? 24000);
const channels = Number(targetFormat?.channels ?? 1);
const bitsPerSample = Number(targetFormat?.bitsPerSample ?? 16);
const bytesPerSample = Math.floor(bitsPerSample / 8);

const silenceBytes = Math.max(0, Math.floor(sampleRate * silenceSeconds * channels * bytesPerSample));
const silenceBuffer = silenceBytes > 0 ? Buffer.alloc(silenceBytes, 0) : Buffer.alloc(0);

for (let i = 0; i < audioSegments.length; i += 1) {
  const pcmBuffer = audioSegments[i].pcm;

  if (!pcmBuffer || pcmBuffer.length === 0) {
    continue;
  }

  if (joinedPcm.length === 0) {
    joinedPcm = pcmBuffer;
    continue;
  }

  if (silenceBytes > 0) {
    joinedPcm = Buffer.concat([joinedPcm, silenceBuffer, pcmBuffer]);
  } else if (crossfadeSeconds > 0) {
    joinedPcm = crossfadePcm(joinedPcm, pcmBuffer, crossfadeSeconds, sampleRate);
  } else {
    joinedPcm = Buffer.concat([joinedPcm, pcmBuffer]);
  }
}

const outputItems = normalizedItems.map((item) => {
  const clone = { ...item };
  delete clone.wavBase64;
  return clone;
});

const chunksTotal = Number(input.chunksTotal ?? outputItems.length ?? 0);
const chunksSuccessRaw = outputItems.filter((item) => item.status === 'success').length;
const failedChunkIndexes = outputItems
  .filter((item) => item.status !== 'success')
  .map((item) => Number(item.chunkIndex ?? 0));

let status = 'success';
if (chunksSuccessRaw <= 0 || joinedPcm.length <= 0) {
  status = 'failed';
} else if (failedChunkIndexes.length > 0) {
  status = 'partialFailed';
}

const firstFailedItem = outputItems
  .filter((item) => item && item.status !== 'success')
  .sort((a, b) => Number(a.chunkIndex ?? 0) - Number(b.chunkIndex ?? 0))[0];
const firstFailedReason = safeText(firstFailedItem?.errorReason);

const totalDurationSec = joinedPcm.length > 0
  ? Math.round((joinedPcm.length / (sampleRate * channels * bytesPerSample)) * 1000) / 1000
  : 0;

const outputFileName = 'tts-' + safeText(input.requestId, Date.now().toString(36)) + '.wav';

const jsonOutput = {
  ...input,
  joinMode: requestedJoinMode === 'crossfade' ? 'crossfade' : 'silence',
  silenceSeconds,
  crossfadeSeconds,
  status,
  audioBase64: '',    // base64 WAV de node sau tu convert
  audioMimeType: 'audio/wav',
  audioFileName: outputFileName,
  sampleRate,
  channels,
  pcmFormat: bitsPerSample === 16 ? 's16le' : ('s' + String(bitsPerSample) + 'le'),
  chunksTotal,
  chunksSuccess: joinedPcm.length > 0 ? chunksSuccessRaw : 0,
  failedChunkIndexes,
  totalDurationSec,
  items: outputItems,
  errorReason: status === 'failed'
    ? safeText(
        firstFailedReason,
        safeText(input.errorReason, failedChunkIndexes.length > 0 ? 'all_chunks_failed' : 'empty_audio'),
      )
    : null,
};

delete jsonOutput.chunks;

if (joinedPcm.length > 0) {
  const header = buildWavHeader(joinedPcm.length, sampleRate, channels, bitsPerSample);
  const wav = Buffer.concat([header, joinedPcm]);
  jsonOutput.audioBase64 = wav.toString('base64');
}

return [{ json: jsonOutput }];

const input = $json ?? {};
const chunk = input.chunks && typeof input.chunks === 'object' && !Array.isArray(input.chunks)
  ? input.chunks
  : (Array.isArray(input.chunks) ? input.chunks[0] : {});

const chunkIndex = Number.isFinite(Number(chunk?.chunkIndex))
  ? Math.floor(Number(chunk.chunkIndex))
  : 0;
const chunkText = String(chunk?.text ?? '').trim();

return {
  ...input,
  chunks: [{
    chunkIndex,
    text: chunkText,
  }],
};

const input = $json ?? {};
const singleChunk = Array.isArray(input.chunks) && input.chunks[0] ? input.chunks[0] : {};
const result = Array.isArray(input.items) && input.items[0] ? input.items[0] : null;

function safeText(value, fallback = '') {
  const text = String(value ?? '').trim();
  return text || fallback;
}

const fallbackResult = {
  chunkIndex: Number(singleChunk.chunkIndex ?? 0),
  text: safeText(singleChunk.text),
  status: 'failed',
  attempts: 0,
  voiceId: safeText(input.voiceId),
  wavBase64: '',
  wavBytes: 0,
  latencyMs: 0,
  errorReason: safeText(input.errorReason, 'chunk_execution_failed'),
};

const chunkResult = result && typeof result === 'object'
  ? { ...fallbackResult, ...result }
  : fallbackResult;

return {
  requestId: input.requestId,
  text: input.text,
  voiceId: safeText(chunkResult.voiceId, safeText(input.voiceId)),
  mode: input.mode,
  maxCharsChunk: input.maxCharsChunk,
  batchSize: input.batchSize,
  joinMode: input.joinMode,
  silenceSeconds: input.silenceSeconds,
  crossfadeSeconds: input.crossfadeSeconds,
  retry: input.retry,
  requestTimeoutSec: input.requestTimeoutSec,
  ttsApiBaseUrl: input.ttsApiBaseUrl,
  chunksTotal: Number(input.chunksTotal ?? 0),
  chunkResult,
};

const rows = $input.all().map((item) => item.json || {});
const base = rows[0] || {};
const items = rows
  .map((row) => row.chunkResult || null)
  .filter((row) => row && typeof row === 'object')
  .sort((a, b) => Number(a.chunkIndex ?? 0) - Number(b.chunkIndex ?? 0));

const chunksSuccess = items.filter((item) => String(item.status || '') === 'success').length;
const failedChunkIndexes = items
  .filter((item) => String(item.status || '') !== 'success')
  .map((item) => Number(item.chunkIndex ?? 0));

let status = 'success';
if (chunksSuccess <= 0) {
  status = 'failed';
} else if (failedChunkIndexes.length > 0) {
  status = 'partialFailed';
}

const firstAudioLatencyMs = items
  .filter((item) => String(item.status || '') === 'success')
  .map((item) => Number(item.latencyMs || 0))
  .filter((ms) => Number.isFinite(ms) && ms >= 0)
  .sort((a, b) => a - b)[0];

return [{
  json: {
    requestId: base.requestId,
    text: base.text,
    voiceId: base.voiceId,
    mode: base.mode,
    maxCharsChunk: base.maxCharsChunk,
    batchSize: base.batchSize,
    batchSizeUsed: 1,
    joinMode: base.joinMode,
    silenceSeconds: base.silenceSeconds,
    crossfadeSeconds: base.crossfadeSeconds,
    retry: base.retry,
    requestTimeoutSec: base.requestTimeoutSec,
    ttsApiBaseUrl: base.ttsApiBaseUrl,
    chunksTotal: Number(base.chunksTotal ?? items.length),
    chunksSuccess,
    failedChunkIndexes,
    firstAudioLatencyMs: Number.isFinite(firstAudioLatencyMs) ? firstAudioLatencyMs : null,
    items,
    status,
    errorReason: status === 'failed' ? 'all_chunks_failed' : null,
  },
}];
